      "groupKey": "1-10|M1|2021|Dec",
      "resourceKind": "q",
      "kind": "Question",
      "sourceMatch": "Module 1 (December 2021 Session) Page 1 of 5 SECTION B – WRITTEN QUESTIONS ( Total: 80 marks ) Answer ALL questions in this section. Marks are indicated at the end of each question",
      "id": "file:///F:/hkicpa%20LP+Past%20paper/M1-10LP+Past%20paper/1-10%20Past%20paper/module1/Module%201%20Question%20Dec%202021.pdf#question-q-p001-1",
